75	/// Per-lemma verdict.
76	#[derive(Debug, Clone, Copy)]
77	pub enum LemmaResult {
78	    Verified,
79	    Falsified,
80	    AnalysisIncomplete,
81	}
82	
83	impl LemmaResult {
84	    fn text(self) -> &'static str {
85	        match self {
86	            LemmaResult::Verified => "verified",
87	            LemmaResult::Falsified => "falsified",
88	            LemmaResult::AnalysisIncomplete => "analysis incomplete",
89	        }
