184	/// A theory processed by a closed batch run.
185	#[derive(Debug, Clone)]
186	pub struct BatchTheory {
187	    /// Name used in the `[Theory <name>]` progress markers (stderr).
188	    pub name: String,
189	    /// The printed theory payload (stdout), or `None` when it was written to an
190	    /// output file instead.
191	    pub payload: Option<String>,
192	    /// Further progress lines the engine emitted for this theory after the five
193	    /// closed phases (stderr), verbatim and newline-terminated. Empty for a plain
194	    /// analyze run; under `--prove` it carries the `[Saturating Sources] …` lines.
195	    pub extra_progress: String,
196	    /// This theory's summary contribution (stdout).
197	    pub summary: Summary,
198	}
199	
200	/// A closed batch run over one or more theories.
201	///
202	/// stderr: the maude preamble, then per theory the five progress markers followed
203	/// by any extra engine progress. stdout: the printed payloads (in order), then one
204	/// combined summary block.
205	pub fn frame_batch(maude: &MaudeInfo, theories: &[BatchTheory]) -> Streams {
206	    let mut s = Streams::default();
207	    s.err.push_str(&maude_preamble(maude));
208	    for t in theories {
209	        s.err.push_str(&progress_block(&t.name, &CLOSED_PHASES));
210	        s.err.push_str(&t.extra_progress);
211	    }
212	    for t in theories {
213	        if let Some(p) = &t.payload {
214	            s.out.push_str(p);
215	        }
216	    }
217	    let summaries: Vec<Summary> = theories.iter().map(|t| t.summary.clone()).collect();
218	    s.out.push_str(&render_summary(&summaries));
219	    s
220	}
221	
222	/// A theory under `--parse-only`: its name (for the single progress marker) and
223	/// its opaque payload.
224	#[derive(Debug, Clone)]
225	pub struct LoadedTheory {
226	    pub name: String,
227	    pub payload: String,
228	}
229	
230	/// A `--parse-only` run: stderr carries one `Theory loaded` marker per theory (no
231	/// preamble); stdout carries the concatenated payloads (no summary block).
232	pub fn frame_parse_only(theories: &[LoadedTheory]) -> Streams {
233	    let mut s = Streams::default();
234	    for t in theories {
235	        s.err.push_str(&progress_line(&t.name, Phase::Loaded));
236	        s.out.push_str(&t.payload);
237	    }
238	    s
239	}
240	
241	/// A `variants` run: stdout carries the variant payload; stderr carries only the
242	/// maude preamble (no progress markers, no summary).
243	pub fn frame_variants(maude: &MaudeInfo, payload: &str) -> Streams {
244	    Streams { out: payload.to_string(), err: maude_preamble(maude) }
245	}
