18	fn s(a: &str) -> String {
19	    a.to_string()
20	}
21	fn argv(items: &[&str]) -> Vec<String> {
22	    items.iter().map(|x| x.to_string()).collect()
23	}
24	fn run_err(items: &[&str]) -> ParseError {
25	    parse_args(&argv(items)).unwrap_err()
26	}
27	fn run_ok(items: &[&str]) -> Args {
28	    match parse_args(&argv(items)).unwrap() {
29	        Parsed::Run(a) => a,
30	        other => panic!("expected Run, got {other:?}"),
31	    }
32	}
