207	#[test]
208	fn haskell_int_accept_reject_matches_reference() {
209	    // Accepted by the reference (exit 0):
210	    for good in ["-5", "0", "5", " 5", "5 ", "  5", "- 5", "0x10", "010", "\t5", "5\n"] {
211	        assert!(read_haskell_int(good).is_some(), "should accept {good:?}");
212	    }
213	    // A value beyond i64 wraps rather than being rejected.
214	    assert!(read_haskell_int("99999999999999999999999").is_some());
215	    // Rejected by the reference (invalid bound given):
216	    for bad in ["", "x", "3.5", "5abc", "+5", "5_0", "-", " "] {
217	        assert!(read_haskell_int(bad).is_none(), "should reject {bad:?}");
218	    }
219	    // Values:
220	    assert_eq!(read_haskell_int("5"), Some(5));
221	    assert_eq!(read_haskell_int("-5"), Some(-5));
222	    assert_eq!(read_haskell_int(" 42 "), Some(42));
223	    assert_eq!(read_haskell_int("0x10"), Some(16));
224	    assert_eq!(read_haskell_int("- 7"), Some(-7));
225	}
