343	/// Extract each theory block's dynamic slots `(analyzed, output, time)` from a
344	/// summary section, so the framing tests are robust to path/timing variation.
345	fn slots(section: &str) -> Vec<(String, Option<String>, f64)> {
346	    let mut out: Vec<(String, Option<String>, f64)> = Vec::new();
347	    let mut cur: Option<(String, Option<String>, f64)> = None;
