350	            if let Some(c) = cur.take() {
351	                out.push(c);
352	            }
353	            cur = Some((a.to_string(), None, 0.0));
354	        } else if let Some(o) = line.strip_prefix("  output:") {
355	            if let Some(c) = cur.as_mut() {
356	                c.1 = Some(o.trim_start().to_string());
357	            }
358	        } else if let Some(t) = line.strip_prefix("  processing time: ") {
359	            if let Some(c) = cur.as_mut() {
360	                c.2 = t.trim_end_matches('s').parse().expect("time");
361	            }
362	        }
363	    }
364	    if let Some(c) = cur.take() {
365	        out.push(c);
366	    }
367	    out
368	}
