1	//! Thin driver exercising the CLI text surface.
2	//!
3	//! Handles the pure-text paths (help, version, parse/validation errors)
4	//! byte-for-byte so they can be verified against the black-box binary. `Run` has
5	//! no prover engine behind it here — real integration wires the typed
6	//! [`cli_clean::Args`] into the prover and uses [`cli_clean::framing`] to wrap its
7	//! output across the two streams.
8	
9	use std::process::exit;
10	
11	use cli_clean::stream::Stream;
12	use cli_clean::version::{frame_version, MaudeInfo, VersionInfo};
13	use cli_clean::{parse_args, Parsed};
14	
15	/// Version slots as observed from the reference build. Real integration injects
16	/// the actual build metadata of the hosting binary.
17	fn observed_version_info() -> VersionInfo {
18	    VersionInfo {
19	        maude: MaudeInfo::default(),
20	        tamarin_version: "1.13.0".to_string(),
21	        copyright_years: "2010-2023".to_string(),
22	        git_description: "0234f6a1abee25677c0accef62de0ac2883b0347 (with uncommited changes), branch: HEAD"
23	            .to_string(),
24	        compiled_at: "2026-07-16 18:33:16.036427196 UTC".to_string(),
25	    }
26	}
27	
28	fn main() {
29	    let argv: Vec<String> = std::env::args().skip(1).collect();
30	    match parse_args(&argv) {
31	        Ok(Parsed::Help(mode)) => {
32	            print!("{}", cli_clean::render_help(mode));
33	            exit(0);
34	        }
35	        Ok(Parsed::Version) => {
36	            let streams = frame_version(&observed_version_info());
37	            print!("{}", streams.out);
38	            eprint!("{}", streams.err);
39	            exit(0);
40	        }
41	        Ok(Parsed::Run(args)) => {
42	            // Text-surface stub: no prover engine in this crate.
43	            eprintln!(
44	                "[cli-clean] parsed: mode={:?} positional={:?} bound={:?} stop_on_trace={:?} output_module={:?} processors={:?}",
45	                args.mode,
46	                args.positional,
47	                args.bound,
48	                args.stop_on_trace,
49	                args.output_module,
50	                args.processors,
51	            );
52	            exit(0);
53	        }
54	        Err(e) => {
55	            match e.stream {
56	                Stream::Out => print!("{}", e.text),
57	                Stream::Err => eprint!("{}", e.text),
58	            }
59	            exit(e.exit_code);
60	        }
61	    }
62	}
